// CreateRequest.js — with Gemini API auto-detection (fixed)
import React, { useState } from 'react';
import { api } from '../services/api';

const PRESETS = [
  { name: 'Connaught Place', lat: 28.6315, lng: 77.2167 },
  { name: 'Lajpat Nagar',   lat: 28.5693, lng: 77.2439 },
  { name: 'Dwarka',          lat: 28.5921, lng: 77.0460 },
  { name: 'Rohini',          lat: 28.7041, lng: 77.1025 },
  { name: 'Saket',           lat: 28.5244, lng: 77.2066 },
];

const DEFAULT = {
  location: '',
  lat: '28.6139',
  lng: '77.2090',
  severity: 'medium',
  description: '',
  type: 'any',
};

export default function CreateRequest({ notify, goPage }) {
  const [form, setForm]           = useState(DEFAULT);
  const [loading, setLoading]     = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [aiResult, setAiResult]   = useState(null);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  // ── Gemini API call (fixed) ────────────────────────────────────────────────
  async function analyzeWithGemini() {
  if (!form.description.trim()) {
    notify('Empty description', 'Please enter a description first.');
    return;
  }

  setAnalyzing(true);
  setAiResult(null);

  try {
    const API_KEY = process.env.REACT_APP_GEMINI_API_KEY;

    if (!API_KEY) {
      notify('Missing API Key', 'Add REACT_APP_GEMINI_API_KEY to your .env file and restart.');
      setAnalyzing(false);
      return;
    }

    const prompt = `
      You are an emergency dispatch AI assistant.
      Analyse this emergency description and respond with ONLY this exact JSON format.
      Do not add any text before or after. Do not use markdown. Do not use code blocks.
      Just the raw JSON object and nothing else.

      {
        "severity": "high",
        "type": "Ambulance"
      }

      severity must be exactly one of: high, medium, low
      type must be exactly one of: Ambulance, Responder, Delivery, any

      Rules:
      - Ambulance: medical emergencies, injuries, cardiac, breathing issues, accidents
      - Responder: fires, crimes, riots, rescues, disasters, security threats
      - Delivery: blood, medicine, oxygen, food, relief supply needs
      - high: life threatening, unconscious, not breathing, critical
      - medium: urgent but stable, moderate injury, conscious but in pain
      - low: non-urgent, minor, routine supply request

      Emergency description: "${form.description}"
    `;

    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${API_KEY}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          contents: [{ parts: [{ text: prompt }] }],
          generationConfig: {
            temperature: 0.1,
            maxOutputTokens: 100,
          },
        }),
      }
    );

    if (!response.ok) {
      const errData = await response.json();
      const message = errData?.error?.message || `HTTP ${response.status}`;
      notify('Gemini API Error', message);
      setAnalyzing(false);
      return;
    }

    const data = await response.json();
    console.log('Gemini raw response:', data);

    const rawText = data?.candidates?.[0]?.content?.parts?.[0]?.text || '';
    console.log('Gemini raw text:', rawText);

    if (!rawText) {
      notify('Empty response', 'Gemini returned nothing. Try again.');
      setAnalyzing(false);
      return;
    }

    // ── Robust JSON extraction ─────────────────────────────────────────────
    let parsed = null;

    // Step 1 — try parsing directly first
    try {
      parsed = JSON.parse(rawText.trim());
    } catch {
      // Step 2 — strip markdown code fences and try again
      const stripped = rawText
        .replace(/```json/gi, '')
        .replace(/```/gi, '')
        .trim();
      try {
        parsed = JSON.parse(stripped);
      } catch {
        // Step 3 — extract JSON using regex (finds first { ... } block)
        const match = rawText.match(/\{[\s\S]*?\}/);
        if (match) {
          try {
            parsed = JSON.parse(match[0]);
          } catch {
            parsed = null;
          }
        }
      }
    }

    // Step 4 — if still null extract values manually using regex
    if (!parsed) {
      console.warn('JSON parse failed, extracting values manually from:', rawText);

      const severityMatch = rawText.match(/"severity"\s*:\s*"(high|medium|low)"/i);
      const typeMatch     = rawText.match(/"type"\s*:\s*"(Ambulance|Responder|Delivery|any)"/i);

      if (severityMatch || typeMatch) {
        parsed = {
          severity: severityMatch ? severityMatch[1].toLowerCase() : 'medium',
          type:     typeMatch     ? typeMatch[1]                   : 'any',
        };
      }
    }

    // Step 5 — if everything failed, show error
    if (!parsed) {
      console.error('Could not extract values from Gemini response:', rawText);
      notify('Parse failed', 'Could not read Gemini response. Try describing the emergency differently.');
      setAnalyzing(false);
      return;
    }

    // Validate and sanitise
    const validSeverities = ['high', 'medium', 'low'];
    const validTypes      = ['Ambulance', 'Responder', 'Delivery', 'any'];

    const severity = validSeverities.includes(parsed.severity?.toLowerCase())
      ? parsed.severity.toLowerCase()
      : 'medium';

    const type = validTypes.includes(parsed.type)
      ? parsed.type
      : 'any';

    // Apply to form
    setForm(f => ({ ...f, severity, type }));
    setAiResult({ severity, type });
    notify('Gemini analysed!', `Severity → ${severity} | Type → ${type}`);

  } catch (err) {
    console.error('Gemini error:', err);
    if (err.message?.includes('Failed to fetch')) {
      notify('Network error', 'Cannot reach Gemini. Check your internet connection.');
    } else {
      notify('Gemini failed', err.message || 'Unknown error. Check browser console (F12).');
    }
  } finally {
    setAnalyzing(false);
  }
}

  // ── Submit ─────────────────────────────────────────────────────────────────
  async function handleSubmit() {
    if (!form.location || !form.lat || !form.lng) {
      notify('Missing fields', 'Please fill in location, latitude and longitude.');
      return;
    }
    setLoading(true);
    try {
      const req   = await api.createRequest({
        ...form,
        lat: parseFloat(form.lat),
        lng: parseFloat(form.lng),
      });
      const alloc = await api.allocate(req.id);
      notify('Allocated!', `${alloc.resourceName} dispatched to ${req.location}`);
      setForm(DEFAULT);
      setAiResult(null);
      goPage(3);
    } catch (err) {
      notify('Error', err.message, 4500);
    } finally {
      setLoading(false);
    }
  }

  return (
    <>
      <p className="page-title">Create Request</p>

      <div className="card">
        <div className="card-title">Request details</div>
        <div className="form-grid">

          <div className="form-group">
            <label>Location name *</label>
            <input
              value={form.location}
              onChange={e => set('location', e.target.value)}
              placeholder="e.g. Sector 12, Delhi"
            />
          </div>

          <div className="form-group">
            <label>Description *</label>
            <input
              value={form.description}
              onChange={e => { set('description', e.target.value); setAiResult(null); }}
              placeholder="Describe the emergency in detail..."
            />
          </div>

          {/* Gemini button */}
          <div className="form-group" style={{ gridColumn: '1 / -1' }}>
            <button
              className="btn"
              onClick={analyzeWithGemini}
              disabled={analyzing || !form.description.trim()}
              style={{
                background: analyzing ? '#f5f5f4' : '#4B6FE4',
                color: analyzing ? '#888' : '#fff',
                border: 'none',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: 8,
                fontWeight: 600,
              }}
            >
              {analyzing ? '🤖 Gemini is analysing...' : '✨ Auto-detect with Gemini AI'}
            </button>

            {aiResult && (
              <div style={{
                marginTop: 8, padding: '8px 12px',
                background: '#E1F5EE', borderRadius: 8,
                fontSize: 13, color: '#085041',
                display: 'flex', gap: 16,
              }}>
                <span>🤖 Gemini detected:</span>
                <strong>Severity → {aiResult.severity}</strong>
                <strong>Type → {aiResult.type}</strong>
              </div>
            )}
          </div>

          <div className="form-group">
            <label>Severity * <span style={{ color: '#4B6FE4', fontSize: 11 }}>(auto-filled by Gemini)</span></label>
            <select value={form.severity} onChange={e => set('severity', e.target.value)}>
              <option value="high">High — immediate danger</option>
              <option value="medium">Medium — urgent but stable</option>
              <option value="low">Low — non-urgent</option>
            </select>
          </div>

          <div className="form-group">
            <label>Resource type <span style={{ color: '#4B6FE4', fontSize: 11 }}>(auto-filled by Gemini)</span></label>
            <select value={form.type} onChange={e => set('type', e.target.value)}>
              <option value="any">Any available</option>
              <option value="Ambulance">🚑 Ambulance</option>
              <option value="Responder">🦺 Responder</option>
              <option value="Delivery">📦 Delivery</option>
            </select>
            <span style={{ fontSize: 11, color: 'var(--muted)', marginTop: 3 }}>
              Gemini sets this automatically — you can still override manually.
            </span>
          </div>

          <div className="form-group">
            <label>Latitude *</label>
            <input type="number" step="0.0001" value={form.lat} onChange={e => set('lat', e.target.value)} />
          </div>

          <div className="form-group">
            <label>Longitude *</label>
            <input type="number" step="0.0001" value={form.lng} onChange={e => set('lng', e.target.value)} />
          </div>

        </div>

        <button className="btn primary full" onClick={handleSubmit} disabled={loading}>
          {loading ? 'Allocating…' : 'Submit + Auto-allocate'}
        </button>
      </div>

      <div className="card">
        <div className="card-title">Quick-fill presets</div>
        <div className="preset-chips">
          {PRESETS.map(p => (
            <button key={p.name} className="btn"
              onClick={() => setForm(f => ({ ...f, location: p.name, lat: String(p.lat), lng: String(p.lng) }))}>
              {p.name}
            </button>
          ))}
        </div>
      </div>
    </>
  );
}
